Stripe Checkout handles payment UI, PCI compliance, and 3D Secure. You create a session server-side and redirect the customer.

```typescript
// app/api/checkout/route.ts
import Stripe from 'stripe';
import { NextResponse } from 'next/server';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

export async function POST(req: Request) {
  const { priceId, userId } = await req.json();

  const session = await stripe.checkout.sessions.create({
    mode: 'subscription',  // or 'payment' for one-time
    payment_method_types: ['card'],
    line_items: [{ price: priceId, quantity: 1 }],
    success_url: `${process.env.NEXT_PUBLIC_URL}/billing?success=true&session_id={CHECKOUT_SESSION_ID}`,
    cancel_url: `${process.env.NEXT_PUBLIC_URL}/billing?canceled=true`,
    customer_email: undefined,  // Let Stripe collect it
    metadata: { userId },
    subscription_data: {
      metadata: { userId },
      trial_period_days: 14,
    },
    allow_promotion_codes: true,
  });

  return NextResponse.json({ url: session.url });
}
```

```typescript
// Client-side redirect
async function handleCheckout(priceId: string) {
  const res = await fetch('/api/checkout', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ priceId, userId: user.id }),
  });
  const { url } = await res.json();
  window.location.href = url;
}
```

Always use `metadata` to link Stripe objects to your database records. The `{CHECKOUT_SESSION_ID}` template in `success_url` lets you verify the session on the success page. Use `mode: 'subscription'` for recurring billing and `mode: 'payment'` for one-time charges.

Webhooks are the backbone of Stripe integration. Always verify signatures, handle events idempotently, and respond quickly.

```typescript
// app/api/webhooks/stripe/route.ts
import Stripe from 'stripe';
import { headers } from 'next/headers';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);
const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET!;

export async function POST(req: Request) {
  const body = await req.text();  // Must be raw body, not JSON
  const headersList = await headers();
  const signature = headersList.get('stripe-signature')!;

  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(body, signature, webhookSecret);
  } catch (err) {
    console.error('Webhook signature verification failed:', err);
    return new Response('Invalid signature', { status: 400 });
  }

  // Idempotency: check if event was already processed
  const processed = await db.processedEvents.findUnique({
    where: { stripeEventId: event.id },
  });
  if (processed) {
    return new Response('Already processed', { status: 200 });
  }

  try {
    switch (event.type) {
      case 'checkout.session.completed': {
        const session = event.data.object as Stripe.Checkout.Session;
        await handleCheckoutCompleted(session);
        break;
      }
      case 'customer.subscription.updated': {
        const subscription = event.data.object as Stripe.Subscription;
        await handleSubscriptionUpdated(subscription);
        break;
      }
      case 'customer.subscription.deleted': {
        const subscription = event.data.object as Stripe.Subscription;
        await handleSubscriptionCanceled(subscription);
        break;
      }
      case 'invoice.payment_failed': {
        const invoice = event.data.object as Stripe.Invoice;
        await handlePaymentFailed(invoice);
        break;
      }
    }

    await db.processedEvents.create({ data: { stripeEventId: event.id } });
  } catch (error) {
    console.error('Webhook handler error:', error);
    return new Response('Handler error', { status: 500 });
  }

  return new Response('OK', { status: 200 });
}
```

Critical: use `req.text()` not `req.json()` — signature verification requires the raw body. Store processed event IDs to handle Stripe's retry mechanism (Stripe retries failed webhooks for up to 3 days). Return 200 quickly; do heavy processing async.

Managing subscription lifecycle requires handling proration, plan changes, and cancellation flows.

```typescript
import Stripe from 'stripe';
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

// Upgrade/downgrade subscription (immediate proration)
async function changeSubscriptionPlan(subscriptionId: string, newPriceId: string) {
  const subscription = await stripe.subscriptions.retrieve(subscriptionId);

  const updated = await stripe.subscriptions.update(subscriptionId, {
    items: [{
      id: subscription.items.data[0].id,
      price: newPriceId,
    }],
    proration_behavior: 'create_prorations',  // or 'none' or 'always_invoice'
  });

  return updated;
}

// Cancel at end of billing period (most common)
async function cancelSubscription(subscriptionId: string) {
  const subscription = await stripe.subscriptions.update(subscriptionId, {
    cancel_at_period_end: true,
  });

  // subscription.current_period_end = when access expires
  return subscription;
}

// Reactivate a canceled (but not yet expired) subscription
async function reactivateSubscription(subscriptionId: string) {
  const subscription = await stripe.subscriptions.update(subscriptionId, {
    cancel_at_period_end: false,
  });
  return subscription;
}

// Immediate cancellation (rare, usually for refunds)
async function cancelImmediately(subscriptionId: string) {
  const subscription = await stripe.subscriptions.cancel(subscriptionId, {
    prorate: true,  // Issue credit for unused time
  });
  return subscription;
}

// Create billing portal for self-service
async function createPortalSession(customerId: string) {
  const session = await stripe.billingPortal.sessions.create({
    customer: customerId,
    return_url: `${process.env.NEXT_PUBLIC_URL}/billing`,
  });
  return session.url;
}
```

The Stripe Billing Portal (`billingPortal.sessions`) provides a hosted UI for customers to manage their subscription, update payment methods, and view invoices — saving you from building these pages yourself.

