RBAC restricts access based on assigned roles. This pattern uses a database-backed role system with middleware enforcement.

```typescript
// types/auth.ts
export type Role = 'owner' | 'admin' | 'member' | 'viewer';

export type Permission =
  | 'project:create' | 'project:read' | 'project:update' | 'project:delete'
  | 'member:invite' | 'member:remove' | 'member:update-role'
  | 'billing:manage' | 'settings:update';

const ROLE_PERMISSIONS: Record<Role, Permission[]> = {
  owner: [
    'project:create', 'project:read', 'project:update', 'project:delete',
    'member:invite', 'member:remove', 'member:update-role',
    'billing:manage', 'settings:update',
  ],
  admin: [
    'project:create', 'project:read', 'project:update', 'project:delete',
    'member:invite', 'member:remove',
    'settings:update',
  ],
  member: [
    'project:create', 'project:read', 'project:update',
  ],
  viewer: [
    'project:read',
  ],
};

export function hasPermission(role: Role, permission: Permission): boolean {
  return ROLE_PERMISSIONS[role]?.includes(permission) ?? false;
}
```

```typescript
// middleware/authorize.ts
import { hasPermission, Permission, Role } from '@/types/auth';

export function authorize(permission: Permission) {
  return async (req: Request) => {
    const { userId, orgId } = await getAuth(req);
    if (!userId || !orgId) {
      return new Response('Unauthorized', { status: 401 });
    }

    const membership = await db.orgMembership.findUnique({
      where: { userId_orgId: { userId, orgId } },
    });

    if (!membership || !hasPermission(membership.role as Role, permission)) {
      return new Response('Forbidden', { status: 403 });
    }

    return null;  // Authorized, continue
  };
}

// Usage in API route
export async function DELETE(req: Request, { params }: { params: { id: string } }) {
  const authError = await authorize('project:delete')(req);
  if (authError) return authError;

  await db.project.delete({ where: { id: params.id } });
  return new Response(null, { status: 204 });
}
```

Define permissions as granular actions, not broad categories. Map roles to permission sets. Check permissions at the API layer, never rely solely on UI hiding. The `owner` role should be irrevocable and unique per organization.

Stripe does not guarantee webhook delivery order. A `customer.subscription.updated` event may arrive before `checkout.session.completed`, causing your handler to fail if it expects the subscription to exist.

**The problem:**
```typescript
// This handler assumes checkout was processed first — WRONG
case 'customer.subscription.updated': {
  const sub = event.data.object as Stripe.Subscription;
  const userId = sub.metadata.userId;

  // This fails if checkout.session.completed hasn't been processed yet
  await db.subscription.update({
    where: { stripeSubscriptionId: sub.id },
    data: { status: sub.status },
  });
  break;
}
```

**Fix — use upsert and fetch from Stripe API:**
```typescript
case 'customer.subscription.updated':
case 'customer.subscription.created': {
  const sub = event.data.object as Stripe.Subscription;

  // Always fetch latest from Stripe to get complete data
  const fullSub = await stripe.subscriptions.retrieve(sub.id, {
    expand: ['default_payment_method', 'latest_invoice'],
  });

  // Upsert handles both creation and update
  await db.subscription.upsert({
    where: { stripeSubscriptionId: sub.id },
    create: {
      stripeSubscriptionId: sub.id,
      stripeCustomerId: sub.customer as string,
      userId: sub.metadata.userId,
      status: fullSub.status,
      priceId: fullSub.items.data[0].price.id,
      currentPeriodEnd: new Date(fullSub.current_period_end * 1000),
    },
    update: {
      status: fullSub.status,
      priceId: fullSub.items.data[0].price.id,
      currentPeriodEnd: new Date(fullSub.current_period_end * 1000),
    },
  });
  break;
}
```

Key principles: (1) Use upsert instead of separate create/update. (2) Fetch the latest object from Stripe API in the handler — the webhook payload may be stale. (3) Store the Stripe object ID as the unique key, not your internal ID. (4) Make every handler idempotent.

Three leading authentication solutions for Next.js with different tradeoffs in control, cost, and features.

**Clerk** — managed auth with UI components:
```typescript
import { clerkMiddleware } from '@clerk/nextjs/server';
export default clerkMiddleware();
// Pre-built <SignIn />, <UserButton />, <OrganizationSwitcher />
// $25/month for 10k MAU, $0.02/MAU after
```

**Auth.js (NextAuth.js v5)** — self-hosted, open source:
```typescript
import NextAuth from 'next-auth';
import GitHub from 'next-auth/providers/github';
import Credentials from 'next-auth/providers/credentials';

export const { handlers, auth, signIn, signOut } = NextAuth({
  providers: [
    GitHub({ clientId: process.env.GITHUB_ID!, clientSecret: process.env.GITHUB_SECRET! }),
    Credentials({
      credentials: { email: {}, password: {} },
      authorize: async (credentials) => {
        const user = await verifyUser(credentials.email, credentials.password);
        return user ?? null;
      },
    }),
  ],
  callbacks: {
    session: ({ session, token }) => ({ ...session, user: { ...session.user, id: token.sub } }),
  },
});
```

**Supabase Auth** — integrated with Supabase database:
```typescript
import { createClient } from '@supabase/supabase-js';
const supabase = createClient(url, anonKey);

await supabase.auth.signInWithOAuth({ provider: 'google' });
await supabase.auth.signUp({ email, password });
const { data: { user } } = await supabase.auth.getUser();
```

| Feature | Clerk | Auth.js | Supabase Auth |
|---------|-------|---------|---------------|
| Cost | $25+/mo | Free | Free (50k MAU) |
| UI components | Yes | No | Partial |
| MFA/Passkeys | Yes | Plugin | Yes |
| Org/Teams | Yes | DIY | DIY |
| Self-hosted | No | Yes | Yes |
| DB integration | External | Your DB | Supabase |
| Setup time | 30 min | 2-4 hours | 1 hour |

Clerk for fast launch with pre-built UI. Auth.js for full control and zero cost. Supabase Auth when already using Supabase.

Multi-tenancy in SaaS isolates data between organizations. The shared database approach uses a `tenantId` column on every table with RLS enforcement.

```sql
-- Prisma schema
-- schema.prisma
model Organization {
  id        String   @id @default(cuid())
  name      String
  slug      String   @unique
  members   Member[]
  projects  Project[]
}

model Member {
  id     String @id @default(cuid())
  userId String
  orgId  String
  role   Role   @default(MEMBER)
  org    Organization @relation(fields: [orgId], references: [id])
  @@unique([userId, orgId])
}

model Project {
  id    String @id @default(cuid())
  name  String
  orgId String
  org   Organization @relation(fields: [orgId], references: [id])
  @@index([orgId])
}
```

```typescript
// middleware/tenant.ts — Extract tenant from request
export async function getTenantContext(req: Request) {
  const { userId } = await getAuth(req);
  const orgSlug = req.headers.get('x-org-slug');

  if (!userId || !orgSlug) throw new Error('Missing auth context');

  const membership = await db.member.findFirst({
    where: { userId, org: { slug: orgSlug } },
    include: { org: true },
  });

  if (!membership) throw new Error('Not a member of this organization');

  return { orgId: membership.orgId, role: membership.role, userId };
}

// API route with tenant isolation
export async function GET(req: Request) {
  const { orgId } = await getTenantContext(req);

  // ALWAYS filter by orgId — never return cross-tenant data
  const projects = await db.project.findMany({
    where: { orgId },  // Tenant boundary
    orderBy: { createdAt: 'desc' },
  });

  return Response.json(projects);
}
```

Critical: every query must include `orgId` in the WHERE clause. Consider using Prisma middleware or a wrapper function to automatically inject the tenant filter, preventing accidental cross-tenant data leaks.

LaunchDarkly provides feature flags with targeting, percentage rollouts, and A/B testing. Server-side evaluation ensures flags work without client-side SDK exposure.

```bash
npm install @launchdarkly/node-server-sdk @launchdarkly/react-client-sdk
```

**Server-side evaluation (recommended for sensitive flags):**
```typescript
// lib/feature-flags.ts
import * as ld from '@launchdarkly/node-server-sdk';

let ldClient: ld.LDClient;

export async function getFeatureFlags() {
  if (!ldClient) {
    ldClient = ld.init(process.env.LAUNCHDARKLY_SDK_KEY!);
    await ldClient.waitForInitialization({ timeout: 5 });
  }
  return ldClient;
}

export async function getFlag<T>(key: string, user: { id: string; email?: string; plan?: string }, defaultValue: T): Promise<T> {
  const client = await getFeatureFlags();
  const context: ld.LDContext = {
    kind: 'user',
    key: user.id,
    email: user.email,
    plan: user.plan,
  };
  return await client.variation(key, context, defaultValue) as T;
}
```

**Server component usage:**
```typescript
import { getFlag } from '@/lib/feature-flags';
import { currentUser } from '@clerk/nextjs/server';

export default async function Dashboard() {
  const user = await currentUser();
  const showNewDashboard = await getFlag('new-dashboard-v2', {
    id: user!.id,
    email: user!.emailAddresses[0]?.emailAddress,
  }, false);

  return showNewDashboard ? <DashboardV2 /> : <DashboardV1 />;
}
```

**Client-side provider:**
```tsx
'use client';
import { LDProvider } from '@launchdarkly/react-client-sdk';

export function FeatureFlagProvider({ children }: { children: React.ReactNode }) {
  return (
    <LDProvider clientSideID={process.env.NEXT_PUBLIC_LD_CLIENT_ID!}>
      {children}
    </LDProvider>
  );
}
```

Use server-side SDK for billing/access flags (prevents client-side tampering). Use client-side SDK for UI-only flags (faster, no server round-trip). Target by user attributes like plan, company, or percentage rollout.

