Every webhook provider uses a signature to verify authenticity. The pattern is similar across Stripe, GitHub, Clerk, and others: compute HMAC, compare with header.

```typescript
import crypto from 'crypto';

// Generic webhook signature verifier
function verifyWebhookSignature({
  payload,
  signature,
  secret,
  algorithm = 'sha256',
}: {
  payload: string;
  signature: string;
  secret: string;
  algorithm?: string;
}): boolean {
  const computed = crypto
    .createHmac(algorithm, secret)
    .update(payload, 'utf8')
    .digest('hex');

  // Timing-safe comparison prevents timing attacks
  const a = Buffer.from(signature);
  const b = Buffer.from(computed);
  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(a, b);
}

// GitHub webhook verification
export async function verifyGitHubWebhook(req: Request): Promise<boolean> {
  const body = await req.text();
  const signature = req.headers.get('x-hub-signature-256');
  if (!signature) return false;

  const hash = 'sha256=' + crypto
    .createHmac('sha256', process.env.GITHUB_WEBHOOK_SECRET!)
    .update(body)
    .digest('hex');

  return crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(hash)
  );
}

// Clerk webhook verification (uses Svix)
import { Webhook } from 'svix';

export async function verifySvixWebhook(req: Request) {
  const body = await req.text();
  const wh = new Webhook(process.env.CLERK_WEBHOOK_SECRET!);

  return wh.verify(body, {
    'svix-id': req.headers.get('svix-id')!,
    'svix-timestamp': req.headers.get('svix-timestamp')!,
    'svix-signature': req.headers.get('svix-signature')!,
  });
}
```

Always use `crypto.timingSafeEqual` — regular string comparison leaks timing information that attackers can exploit. Always read the raw body (`req.text()`) — JSON parsing and re-stringifying changes whitespace and field order, breaking signatures.

Supabase Auth integrates with PostgreSQL RLS policies, making database-level security automatic based on the authenticated user.

```bash
npm install @supabase/supabase-js @supabase/ssr
```

```typescript
// lib/supabase/server.ts
import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';

export async function createClient() {
  const cookieStore = await cookies();
  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() { return cookieStore.getAll(); },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value, options }) => {
            cookieStore.set(name, value, options);
          });
        },
      },
    }
  );
}
```

```typescript
// app/dashboard/page.tsx
import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';

export default async function DashboardPage() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) redirect('/login');

  // RLS automatically filters to user's data
  const { data: projects } = await supabase
    .from('projects')
    .select('*')
    .order('created_at', { ascending: false });

  return <ProjectList projects={projects ?? []} />;
}
```

**RLS policy (SQL):**
```sql
ALTER TABLE projects ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own projects"
  ON projects FOR SELECT
  USING (auth.uid() = user_id);

CREATE POLICY "Users can insert own projects"
  ON projects FOR INSERT
  WITH CHECK (auth.uid() = user_id);
```

RLS policies run at the database level — even if application code has a bug, users can only access their own data. `auth.uid()` is a Supabase function that returns the authenticated user's ID from the JWT.

Metered billing charges customers based on actual usage (API calls, storage, compute time). Stripe tracks usage records and invoices at the end of each billing period.

```typescript
import Stripe from 'stripe';
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

// Create a metered price in Stripe Dashboard or via API:
// pricing_model: 'per_unit' or 'tiered'
// recurring: { interval: 'month', usage_type: 'metered' }

// Report usage for a subscription item
async function reportUsage(subscriptionItemId: string, quantity: number) {
  await stripe.subscriptionItems.createUsageRecord(subscriptionItemId, {
    quantity,
    timestamp: Math.floor(Date.now() / 1000),
    action: 'increment',  // or 'set' for absolute value
  });
}

// Middleware to track API usage
export async function trackApiUsage(userId: string) {
  // Increment counter in Redis (batch report to Stripe)
  const count = await redis.incr(`usage:${userId}:${currentMonth()}`);

  // Report to Stripe every 100 calls (batching reduces API calls)
  if (count % 100 === 0) {
    const sub = await db.subscription.findUnique({
      where: { userId },
      select: { stripeSubscriptionItemId: true },
    });
    if (sub?.stripeSubscriptionItemId) {
      await reportUsage(sub.stripeSubscriptionItemId, 100);
    }
  }
}

// Get current usage for display
async function getCurrentUsage(subscriptionItemId: string) {
  const summary = await stripe.subscriptionItems.listUsageRecordSummaries(
    subscriptionItemId,
    { limit: 1 }
  );
  return summary.data[0]?.total_usage ?? 0;
}
```

Batch usage reports to avoid Stripe rate limits (100/second). Use Redis for real-time counting and flush to Stripe periodically. At period end, Stripe automatically generates an invoice based on accumulated usage records.

Stripe webhook signature verification fails with a 400 error when the framework parses the body as JSON before you can verify the raw signature.

**Error:**
```
Stripe webhook Error: No signatures found matching the expected signature for payload.
Are you passing the raw request body you received from Stripe?
```

**Cause:** Next.js App Router automatically parses request bodies. Using `req.json()` changes the body format, breaking signature verification.

**Fix for App Router (route.ts):**
```typescript
// app/api/webhooks/stripe/route.ts
import Stripe from 'stripe';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);

export async function POST(req: Request) {
  // CORRECT: Use req.text() for raw body
  const body = await req.text();
  const signature = req.headers.get('stripe-signature')!;

  const event = stripe.webhooks.constructEvent(
    body,
    signature,
    process.env.STRIPE_WEBHOOK_SECRET!
  );

  // Process event...
  return new Response('OK', { status: 200 });
}
```

**Fix for Pages Router (pages/api/):**
```typescript
// pages/api/webhooks/stripe.ts
import { buffer } from 'micro';
import type { NextApiRequest, NextApiResponse } from 'next';

// Disable body parsing for this route
export const config = { api: { bodyParser: false } };

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  const body = (await buffer(req)).toString();
  const signature = req.headers['stripe-signature']!;

  const event = stripe.webhooks.constructEvent(
    body,
    signature,
    process.env.STRIPE_WEBHOOK_SECRET!
  );

  res.status(200).json({ received: true });
}
```

In App Router, `req.text()` returns the raw body correctly. In Pages Router, you must disable `bodyParser` and use `micro`'s `buffer()` to get the raw body.

For simple projects, you can build feature flags with a database table and server-side evaluation, avoiding LaunchDarkly/PostHog costs.

```sql
-- Database schema
CREATE TABLE feature_flags (
  id TEXT PRIMARY KEY,
  key TEXT UNIQUE NOT NULL,
  enabled BOOLEAN DEFAULT false,
  percentage INTEGER DEFAULT 0,  -- 0-100 for gradual rollout
  allowed_user_ids TEXT[] DEFAULT '{}',
  allowed_plans TEXT[] DEFAULT '{}',
  metadata JSONB DEFAULT '{}',
  created_at TIMESTAMP DEFAULT NOW()
);
```

```typescript
// lib/feature-flags.ts
import { cache } from 'react';
import { db } from '@/lib/db';

type FlagContext = {
  userId: string;
  plan?: string;
  email?: string;
};

// Cache per request in React Server Components
export const getFlags = cache(async () => {
  return await db.featureFlag.findMany();
});

export async function isEnabled(key: string, context: FlagContext): Promise<boolean> {
  const flags = await getFlags();
  const flag = flags.find(f => f.key === key);

  if (!flag) return false;
  if (!flag.enabled) return false;

  // Check user allowlist
  if (flag.allowedUserIds.includes(context.userId)) return true;

  // Check plan allowlist
  if (context.plan && flag.allowedPlans.includes(context.plan)) return true;

  // Percentage rollout (deterministic by user ID)
  if (flag.percentage > 0) {
    const hash = simpleHash(context.userId + key);
    return (hash % 100) < flag.percentage;
  }

  return flag.allowedUserIds.length === 0 && flag.allowedPlans.length === 0;
}

function simpleHash(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash);
}
```

Usage:
```typescript
if (await isEnabled('new-pricing-page', { userId: user.id, plan: user.plan })) {
  return <NewPricingPage />;
}
```

The deterministic hash ensures the same user always gets the same result for a given flag. Cache flags per request with React's `cache()` to avoid repeated DB queries in a single render.

