  const features: Record<string, string[]> = {
    hobby: ['projects:3', 'members:1'],
    pro: ['projects:unlimited', 'members:5', 'api-access'],
    team: ['projects:unlimited', 'members:unlimited', 'api-access', 'sso', 'audit-log'],
