A middleware stack that resolves tenant context, checks permissions, and injects tenant-scoped database access into every API request.

```typescript
// lib/tenant-middleware.ts
import { NextRequest, NextResponse } from 'next/server';

export type TenantContext = {
  userId: string;
  orgId: string;
  orgSlug: string;
  role: 'owner' | 'admin' | 'member' | 'viewer';
};

const contextMap = new WeakMap<Request, TenantContext>();

export function setTenantContext(req: Request, ctx: TenantContext) {
  contextMap.set(req, ctx);
}

export function getTenantContext(req: Request): TenantContext {
  const ctx = contextMap.get(req);
  if (!ctx) throw new Error('Tenant context not initialized');
  return ctx;
}

// Higher-order function for tenant-scoped API routes
export function withTenant(
  handler: (req: NextRequest, ctx: TenantContext) => Promise<Response>,
  options?: { requiredRole?: TenantContext['role'] }
) {
  return async (req: NextRequest): Promise<Response> => {
    try {
      const { userId } = await getAuth(req);
      if (!userId) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

      const orgSlug = req.headers.get('x-org-slug') || req.nextUrl.searchParams.get('org');
      if (!orgSlug) return NextResponse.json({ error: 'Missing organization' }, { status: 400 });

      const membership = await db.orgMembership.findFirst({
        where: { userId, org: { slug: orgSlug } },
        include: { org: true },
      });

      if (!membership) return NextResponse.json({ error: 'Forbidden' }, { status: 403 });

      const ROLE_HIERARCHY = { owner: 3, admin: 2, member: 1, viewer: 0 };
      if (options?.requiredRole) {
        const required = ROLE_HIERARCHY[options.requiredRole];
        const actual = ROLE_HIERARCHY[membership.role as keyof typeof ROLE_HIERARCHY];
        if (actual < required) return NextResponse.json({ error: 'Insufficient role' }, { status: 403 });
      }

      const ctx: TenantContext = {
        userId, orgId: membership.orgId, orgSlug, role: membership.role as TenantContext['role'],
      };

      return handler(req, ctx);
    } catch (error) {
      console.error('Tenant middleware error:', error);
      return NextResponse.json({ error: 'Internal error' }, { status: 500 });
    }
  };
}

// Usage
export const DELETE = withTenant(
  async (req, ctx) => {
    const { id } = await req.json();
    await db.project.delete({ where: { id, orgId: ctx.orgId } });
    return new Response(null, { status: 204 });
  },
  { requiredRole: 'admin' }
);
```

The `withTenant` wrapper handles auth, tenant resolution, and role checking in one place. Every database query inside the handler must include `orgId` from the context to maintain tenant isolation.

Clerk fires webhooks for user events (created, updated, deleted). If your database gets out of sync with Clerk, users experience broken profiles or missing data.

**Common error scenario:**
User signs up, `user.created` webhook fails silently, user can authenticate but has no database record.

**Robust webhook handler:**
```typescript
// app/api/webhooks/clerk/route.ts
import { Webhook } from 'svix';
import { headers } from 'next/headers';
import type { WebhookEvent } from '@clerk/nextjs/server';

export async function POST(req: Request) {
  const body = await req.text();
  const headersList = await headers();

  const wh = new Webhook(process.env.CLERK_WEBHOOK_SECRET!);
  let event: WebhookEvent;

  try {
    event = wh.verify(body, {
      'svix-id': headersList.get('svix-id')!,
      'svix-timestamp': headersList.get('svix-timestamp')!,
      'svix-signature': headersList.get('svix-signature')!,
    }) as WebhookEvent;
  } catch {
    return new Response('Invalid signature', { status: 400 });
  }

  switch (event.type) {
    case 'user.created':
    case 'user.updated': {
      const { id, email_addresses, first_name, last_name, image_url } = event.data;
      const primaryEmail = email_addresses.find(e => e.id === event.data.primary_email_address_id);

      await db.user.upsert({
        where: { clerkId: id },
        create: {
          clerkId: id,
          email: primaryEmail?.email_address ?? '',
          name: [first_name, last_name].filter(Boolean).join(' '),
          avatarUrl: image_url,
        },
        update: {
          email: primaryEmail?.email_address ?? '',
          name: [first_name, last_name].filter(Boolean).join(' '),
          avatarUrl: image_url,
        },
      });
      break;
    }
    case 'user.deleted': {
      if (event.data.id) {
        await db.user.delete({ where: { clerkId: event.data.id } }).catch(() => {});
      }
      break;
    }
  }

  return new Response('OK', { status: 200 });
}
```

**Fallback sync for missed webhooks:**
```typescript
// Middleware: ensure user exists in DB on every request
import { clerkClient } from '@clerk/nextjs/server';

async function ensureUserInDb(clerkId: string) {
  const existing = await db.user.findUnique({ where: { clerkId } });
  if (existing) return existing;

  // Webhook may have failed — sync from Clerk API
  const clerkUser = await (await clerkClient()).users.getUser(clerkId);
  return db.user.create({
    data: {
      clerkId,
      email: clerkUser.emailAddresses[0]?.emailAddress ?? '',
      name: `${clerkUser.firstName ?? ''} ${clerkUser.lastName ?? ''}`.trim(),
    },
  });
}
```

Always use `upsert` to handle both `user.created` and `user.updated`. Add a fallback sync in middleware to catch missed webhooks.

