  projects      Project[]
}

model OrgMembership {
  id     String @id @default(cuid())
  userId String
  orgId  String
  role   String @default("member")
  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)

  @@unique([userId, orgId])
}
```

**Step 4 — API route with sync logic:**
```typescript
// Helper: sync user data from Clerk event payload
async function syncUser(data: any) {
  const email = data.email_addresses?.find(
    (e: any) => e.id === data.primary_email_address_id
  )?.email_address;

  return db.user.upsert({
    where: { clerkId: data.id },
    create: {
      clerkId: data.id,
      email: email ?? '',
      name: [data.first_name, data.last_name].filter(Boolean).join(' ') || null,
      avatarUrl: data.image_url,
    },
    update: {
      email: email ?? undefined,
      name: [data.first_name, data.last_name].filter(Boolean).join(' ') || undefined,
      avatarUrl: data.image_url,
    },
  });
}
```

Always use `upsert` — webhooks can arrive out of order. Store `clerkId` as the foreign key to Clerk. Query your own database for user data in server components; use Clerk's `useUser()` only in client components for real-time auth state.

Never call the Stripe API directly from the browser. The secret key would be exposed and CORS blocks the requests anyway.

**Error:**
```
Access to fetch at 'https://api.stripe.com/v1/payment_intents'
from origin 'https://myapp.com' has been blocked by CORS policy
```

**WRONG — calling Stripe from browser:**
```typescript
// Client-side — NEVER DO THIS
const res = await fetch('https://api.stripe.com/v1/payment_intents', {
  method: 'POST',
  headers: {
    'Authorization': `Bearer sk_live_xxx`,  // SECRET KEY EXPOSED!
  },
});
```

**CORRECT — proxy through your API:**
```typescript
// Client-side
async function createPaymentIntent(amount: number) {
  const res = await fetch('/api/payment-intent', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ amount }),
  });
  return res.json();  // Returns { clientSecret: 'pi_xxx_secret_xxx' }
}

// Server-side API route
import Stripe from 'stripe';
const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!);  // Server only!

export async function POST(req: Request) {
  const { amount } = await req.json();
  const paymentIntent = await stripe.paymentIntents.create({
    amount,
    currency: 'usd',
  });
  return Response.json({ clientSecret: paymentIntent.client_secret });
}

// Client-side — use Stripe.js with the client secret
import { loadStripe } from '@stripe/stripe-js';
const stripePromise = loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY!);

const stripe = await stripePromise;
const { error } = await stripe!.confirmPayment({
  clientSecret,
  elements,
  confirmParams: { return_url: `${window.location.origin}/success` },
});
```

The pattern: create payment resources server-side with the secret key, return the `client_secret` to the browser, and use Stripe.js (which uses the publishable key) to complete the payment.

A team invitation flow: admin invites by email, system sends an invite link, recipient accepts and joins the organization.

```typescript
// lib/invitations.ts
import crypto from 'crypto';
import { sendEmail } from '@/lib/email';

export async function createInvitation(orgId: string, email: string, role: string, invitedBy: string) {
  const token = crypto.randomBytes(32).toString('hex');
  const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000); // 7 days

  const invitation = await db.invitation.create({
    data: {
      orgId,
      email: email.toLowerCase(),
      role,
      token,
      expiresAt,
      invitedBy,
    },
  });

  const org = await db.org.findUnique({ where: { id: orgId } });
  const inviteUrl = `${process.env.NEXT_PUBLIC_URL}/invite/${token}`;

  await sendEmail({
    to: email,
    subject: `You've been invited to ${org!.name}`,
    html: `
      <p>You've been invited to join <strong>${org!.name}</strong> as a ${role}.</p>
      <a href="${inviteUrl}">Accept Invitation</a>
      <p>This invitation expires in 7 days.</p>
    `,
  });

  return invitation;
}
```

```typescript
// app/invite/[token]/page.tsx
import { auth } from '@clerk/nextjs/server';
import { redirect } from 'next/navigation';

export default async function AcceptInvitePage({ params }: { params: { token: string } }) {
  const { userId } = await auth();

  const invitation = await db.invitation.findUnique({
    where: { token: params.token },
    include: { org: true },
  });

  if (!invitation || invitation.expiresAt < new Date() || invitation.acceptedAt) {
    return <div>This invitation is invalid or has expired.</div>;
  }

  if (!userId) {
    // Redirect to sign-up, then back here
    redirect(`/sign-up?redirect_url=/invite/${params.token}`);
  }

  return <AcceptInviteForm invitation={invitation} />;
}

// API: Accept invitation
export async function POST(req: Request, { params }: { params: { token: string } }) {
  const { userId } = await auth();

  const invitation = await db.invitation.findUnique({ where: { token: params.token } });
  if (!invitation || invitation.expiresAt < new Date()) {
    return Response.json({ error: 'Invalid invitation' }, { status: 400 });
  }

  await db.$transaction([
    db.orgMembership.create({
      data: { userId: userId!, orgId: invitation.orgId, role: invitation.role },
    }),
    db.invitation.update({
      where: { id: invitation.id },
      data: { acceptedAt: new Date(), acceptedBy: userId },
    }),
  ]);

  return Response.json({ orgId: invitation.orgId });
}
```

Use `crypto.randomBytes(32)` for secure tokens, not UUIDs. Set an expiration date. Use a database transaction to atomically create the membership and mark the invitation as accepted. Redirect unauthenticated users to sign-up with a return URL.

