Track API usage per tenant for billing and enforce rate limits to prevent abuse. Use Redis for real-time counting.

```typescript
// lib/rate-limiter.ts
import { Redis } from '@upstash/redis';

const redis = new Redis({
  url: process.env.UPSTASH_REDIS_URL!,
  token: process.env.UPSTASH_REDIS_TOKEN!,
});

interface RateLimitResult {
  allowed: boolean;
  remaining: number;
  resetAt: Date;
}

export async function checkRateLimit(
  identifier: string,
  limit: number,
  windowSeconds: number
): Promise<RateLimitResult> {
  const key = `rate:${identifier}`;
  const now = Math.floor(Date.now() / 1000);
  const windowStart = now - windowSeconds;

  // Sliding window using sorted set
  const pipeline = redis.pipeline();
  pipeline.zremrangebyscore(key, 0, windowStart);
  pipeline.zadd(key, { score: now, member: `${now}:${Math.random()}` });
  pipeline.zcard(key);
  pipeline.expire(key, windowSeconds);

  const results = await pipeline.exec();
  const count = results[2] as number;

  return {
    allowed: count <= limit,
    remaining: Math.max(0, limit - count),
    resetAt: new Date((now + windowSeconds) * 1000),
  };
}

// Middleware
export async function rateLimitMiddleware(req: Request, orgId: string) {
  const plan = await getOrgPlan(orgId);
  const limits: Record<string, number> = {
    free: 100,     // 100 requests per minute
    pro: 1000,     // 1000 requests per minute
    enterprise: 10000,
  };

  const limit = limits[plan] ?? limits.free;
  const result = await checkRateLimit(`api:${orgId}`, limit, 60);

  if (!result.allowed) {
    return new Response(JSON.stringify({ error: 'Rate limit exceeded' }), {
      status: 429,
      headers: {
        'X-RateLimit-Limit': String(limit),
        'X-RateLimit-Remaining': String(result.remaining),
        'X-RateLimit-Reset': result.resetAt.toISOString(),
        'Retry-After': String(60),
      },
    });
  }

  return null;  // Allowed
}
```

The sliding window algorithm using Redis sorted sets provides accurate rate limiting. Return `X-RateLimit-*` headers so clients can self-regulate. Use Upstash Redis for serverless compatibility (HTTP-based, no persistent connections needed).
